import Header from './Header';
import Content from './Content';
import Footer from './Footer';
import Additems from './Additems';
import { useEffect, useState } from 'react';
import ListItems from './ListItems';
import SearchItem from './SearchItem';

function App() {
  const API_URL='http://localhost:3500/items';
  useEffect(()=>{
    const fetchItems=async()=>{
      try {
        const response=await fetch(API_URL);
        const listItems= await response.json();
        setItems(listItems)
      } catch (error) {
        console.log(error.stack)
      }
    }
  (async ()=> await fetchItems())()
  },[])
  const[items,setItems]=useState([])
    const handleChange = (id)=>
    {
      const ListItems =items.map(items => (items.id==id) ?{...items,checked:!items.checked}:items);
      setItems(ListItems);
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const changeDelete=(id)=>
    {
      const ListItems=items.filter(items =>items.id!==id);
      setItems(ListItems);
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const addItem=(activity)=>{
      const id=(items.length)?items[items.length -1].id+1:1
      const addNewItem={id,activity,checked:false}
      const ListItems=[...items,addNewItem]
      setItems(ListItems)
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const [newItem,setNewItem]=useState('')
    const handleSumbit=(e)=>{
      e.preventDefault();
      if(!newItem) return;
      addItem(newItem)
      setNewItem('')
    }
    const[search,setSearch]=useState('')
  return (
    <div className="div">
    <Header title="To-Do Lists"/>
    <SearchItem search={search} setSearch={setSearch}/>
    <Additems newItem={newItem} setNewItem={setNewItem} handleSumbit={handleSumbit}/>
    <Content items={items.filter(items=>((items.activity).toLowerCase().includes(search.toLowerCase())))} changeDelete={changeDelete} handleChange={handleChange}/>
    <Footer items={items}/>
    </div>
  );
}

export default App;
